import{_ as a,o as i,c as e,a2 as n}from"./chunks/framework.BuL2a98s.js";const k=JSON.parse('{"title":"Usar DevLab","description":"","frontmatter":{},"headers":[],"relativePath":"guide/devlab.md","filePath":"guide/devlab.md"}'),l={name:"guide/devlab.md"};function t(p,s,o,d,h,r){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="usar-devlab" tabindex="-1">Usar DevLab <a class="header-anchor" href="#usar-devlab" aria-label="Permalink to &quot;Usar DevLab&quot;">​</a></h1><p>DevLab es el flujo principal de este repositorio para compilar y cargar los ejemplos FPGA sin depender de <code>make</code>. Cada ejemplo compatible contiene un archivo <code>devlab.toml</code> para Verilog y, cuando aplica, un <code>devlab-vhdl.toml</code> para VHDL.</p><h2 id="requisitos" tabindex="-1">Requisitos <a class="header-anchor" href="#requisitos" aria-label="Permalink to &quot;Requisitos&quot;">​</a></h2><ul><li>Python 3.11 o posterior.</li><li>DevLab y OSS CAD Suite instalados.</li><li>GHDL si se van a compilar fuentes VHDL.</li><li>Una tarjeta Gowin compatible conectada por USB para cargar el bitstream.</li></ul><p>Antes de continuar, sigue la instalación correspondiente a tu sistema:</p><ul><li><a href="./windows">Windows</a>, incluida la configuración del controlador USB y el soporte GHDL independiente.</li><li><a href="./linux">Linux</a>, incluidos el entorno virtual y los permisos <code>udev</code>.</li></ul><h2 id="verificar-el-entorno" tabindex="-1">Verificar el entorno <a class="header-anchor" href="#verificar-el-entorno" aria-label="Permalink to &quot;Verificar el entorno&quot;">​</a></h2><p>Ejecuta el diagnóstico antes del primer build:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">devlab</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">devlab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><p>Si Windows no encuentra el ejecutable <code>devlab</code>, antepone <code>python -m</code> a los mismos comandos:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m devlab </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">version</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m devlab doctor</span></span></code></pre></div><p>Si <code>python</code> selecciona una instalación distinta de aquella donde está DevLab, usa el lanzador de Windows para elegir la versión correcta. Por ejemplo:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">list</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">py </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-3.14</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m devlab </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">version</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">py </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-3.14</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m devlab doctor</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">py </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-3.14</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">m devlab build</span></span></code></pre></div><p>El valor <code>3.14</code> es un ejemplo: sustitúyelo por la versión que contiene DevLab y utiliza la misma selección para los demás comandos.</p><p><code>doctor</code> comprueba las herramientas de OSS CAD Suite. GHDL solamente es necesario para compilar configuraciones VHDL.</p><h2 id="compilar-verilog" tabindex="-1">Compilar Verilog <a class="header-anchor" href="#compilar-verilog" aria-label="Permalink to &quot;Compilar Verilog&quot;">​</a></h2><p>Entra al directorio de un ejemplo y ejecuta el build predeterminado:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> digital-labs/01_sumador_n_bits</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">devlab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>El archivo <code>devlab.toml</code> selecciona las fuentes Verilog:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">top = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;top&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sources = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;src/digital_labs.v&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;src/top.v&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">constraints = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pins.cst&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">build_dir = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;build&quot;</span></span></code></pre></div><h2 id="compilar-vhdl" tabindex="-1">Compilar VHDL <a class="header-anchor" href="#compilar-vhdl" aria-label="Permalink to &quot;Compilar VHDL&quot;">​</a></h2><p>Selecciona explícitamente la configuración VHDL:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">devlab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> devlab-vhdl.toml</span></span></code></pre></div><p>El archivo alternativo usa la fuente VHDL autocontenida:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">top = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;top&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sources = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;src/top.vhd&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">constraints = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;pins.cst&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">build_dir = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;build&quot;</span></span></code></pre></div><p>En Windows, DevLab no depende del plugin <code>yosys-ghdl</code>. Convierte primero VHDL a Verilog con GHDL y entrega el archivo generado a Yosys:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>VHDL -&gt; GHDL --synth --out=verilog -&gt; Yosys -&gt; nextpnr -&gt; gowin_pack</span></span></code></pre></div><p>Consulta <a href="./windows#soporte-vhdl-ghdl-en-windows">Soporte VHDL/GHDL en Windows</a> para instalar GHDL y verificar esta etapa con <code>devlab build --dry-run</code>.</p><h2 id="cargar-en-sram" tabindex="-1">Cargar en SRAM <a class="header-anchor" href="#cargar-en-sram" aria-label="Permalink to &quot;Cargar en SRAM&quot;">​</a></h2><p>Después de un build correcto, carga el bitstream:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">devlab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flash</span></span></code></pre></div><p>La configuración de los ejemplos usa la Tang Nano 9K y carga en SRAM:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">flash</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">board = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tangnano9k&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mode = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sram&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">verify = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p>Si se utiliza otra tarjeta, hay que ajustar <code>board</code>, el dispositivo FPGA y <code>pins.cst</code>. El archivo CST conecta los puertos del diseño con los pines físicos; no se genera automáticamente para una tarjeta diferente.</p><h2 id="flujo-de-trabajo-recomendado" tabindex="-1">Flujo de trabajo recomendado <a class="header-anchor" href="#flujo-de-trabajo-recomendado" aria-label="Permalink to &quot;Flujo de trabajo recomendado&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">devlab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">devlab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">devlab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> flash</span></span></code></pre></div><p>Para revisar los comandos sin ejecutar la síntesis:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">devlab</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --dry-run</span></span></code></pre></div><p>En Windows también se puede usar <code>python -m devlab</code> en cada línea.</p><h2 id="estructura-de-un-ejemplo" tabindex="-1">Estructura de un ejemplo <a class="header-anchor" href="#estructura-de-un-ejemplo" aria-label="Permalink to &quot;Estructura de un ejemplo&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ejemplo/</span></span>
<span class="line"><span>|-- devlab.toml</span></span>
<span class="line"><span>|-- devlab-vhdl.toml</span></span>
<span class="line"><span>|-- pins.cst</span></span>
<span class="line"><span>|-- src/</span></span>
<span class="line"><span>|   |-- top.v</span></span>
<span class="line"><span>|   |-- top.vhd</span></span>
<span class="line"><span>|   \`-- digital_labs.v</span></span>
<span class="line"><span>\`-- README.md</span></span></code></pre></div><p>Los ejemplos básicos no siempre necesitan <code>digital_labs.v</code>; los laboratorios digitales lo usan para separar módulos reutilizables del <code>top</code>.</p><h2 id="problemas-frecuentes" tabindex="-1">Problemas frecuentes <a class="header-anchor" href="#problemas-frecuentes" aria-label="Permalink to &quot;Problemas frecuentes&quot;">​</a></h2><ul><li>Si <code>devlab</code> no está en <code>PATH</code>, usa <code>python -m devlab</code>. En Windows, si ese comando elige otra instalación, usa <code>py -&lt;versión&gt; -m devlab</code>; por ejemplo, <code>py -3.14 -m devlab build</code>.</li><li>Si falla la asignación de pines con <code>ERROR: Unconstrained IO</code>, revisa <a href="./cst"><code>pins.cst</code></a>; GHDL y Yosys ya terminaron su etapa.</li><li>Si Windows bloquea la instalación o algún ejecutable de síntesis, consulta <a href="./windows#solucion-de-problemas">Solución de problemas en Windows</a>.</li><li>Si <code>flash</code> no encuentra la tarjeta, revisa Zadig en Windows o las reglas <code>udev</code> en Linux.</li></ul><h2 id="siguiente-paso" tabindex="-1">Siguiente paso <a class="header-anchor" href="#siguiente-paso" aria-label="Permalink to &quot;Siguiente paso&quot;">​</a></h2><p>Revisa <a href="./cst">Archivos CST</a> para aprender a conectar las entradas y salidas del HDL con los pines físicos de la tarjeta.</p>`,46)])])}const u=a(l,[["render",t]]);export{k as __pageData,u as default};
